#include <bits/stdc++.h>
using namespace std;
int n,k,ehh,num;
unordered_map<int,int> aa;
int main() {
	ios::sync_with_stdio(0),cin.tie(0),cout.tie(0);
	cin>>n>>k;
	aa[0]=1;
	for(int i=1; i<=n; i++) {
		int x;
		cin>>x;
		ehh^=x;
		if(ehh==k||aa.find((ehh^k))!=aa.end()) {
			num++;
			aa.clear();
			aa[0]=1;
			ehh=0;
		} else {
			aa[ehh]=1;
		}
	}
	cout<<num;
	return 0;
}
